const r={name:"Valnöt",icon:"valnot",category:"frukt",family:"Valnötsväxter",familyLatin:"Juglandaceae",perennial:!0,lifespan:"200+ år",difficulty:"Medel",difficultyWhy:"Själva odlingen är inte svår - ett etablerat valnötsträd sköter sig i princip självt. Utmaningen är tålamod (ympade träd ger nötter efter 3-5 år), rätt sortval för din zon, och att senvårfrosten inte slår ut blomningen.",zones:{outdoor:[1,2,3],indoor:null,greenhouse:null},days:"Skörd år 3-5 (ympad), 8-15 (frösodd)",spacing:"8-12 m",spacingNote:"Valnötsträd blir STORA. Broadview är kompaktare (6-8 m) men ge ändå utrymme.",rowSpacing:"10-15 m",depth:"Rotklumpens djup",depthNote:"Valnöten har en kraftig pålrot - gräv djupt och brett. Plantera ALDRIG djupare än rotklumpen suttit.",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Valnöten vill ha minst 6-8 timmars direkt sol. Vindskyddat läge är minst lika viktigt som solen - senvårfrost och kall vind är de verkliga fienderna."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Etablerade träd tål ner mot -25°C i vintervila. MEN: blomknopparna är känsliga som fjärilar på våren - en senvårfrost kan radera ut hela årets skörd på en natt. Sorter med sen bladsprickning (Fernor) minskar risken."},wind:{level:"Skyddat",detail:"Vindskyddat läge är kritiskt. Kall vind stör blomningen och torkar ut unga träd. En skyddad sydvänd plats mot byggnad eller häck är idealiskt."}},watering:{need:"Medel",icon:"water",summary:"Etablerade valnötsträd klarar sig ofta på regnvatten tack vare de djupa pålrötterna. Nyplanterade träd behöver regelbunden vattning de första åren.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress nu ger dålig pollination."},{phase:"Sommar (nötutveckling)",need:"Medel",tip:"Vattna jämnt under nötutvecklingen. Ojämn vattning kan ge kärnan problem att fylla skalet ordentligt."},{phase:"Höst",need:"Låg",tip:"Minska vattningen. Trädet förbereder sig för vintern."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd - pålroten etableras de första 2-3 åren","Vattnar för mycket - valnöten tål inte vattensjuk mark"],tip:"Mulcha runt trädet med gräsklipp eller kompost - det håller fukt och minskar ogräs. Lämna 15 cm fritt runt stammen. Etablerade träd med djupa pålrötter (3-5 m!) klarar torka förvånansvärt bra."},soil:"Valnöten vill ha djup, väldränerad, näringsrik jord. Den tål de flesta jordtyper utom extrem lera eller ren sand. Djupa pålrötter (3-5 meter) gör att den trivs i jord andra träd struntar i.",soilTips:["Gräv en stor grop - minst dubbelt så bred som rotklumpen och rejält djup","Blanda in kompost i den uppgrävda jorden","Kalka om pH är under 6.0 - valnöten gillar lätt kalkrik jord","Undvik mark med högt grundvatten - stående vatten dödar rötterna"],timeline:{1:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Beskärning",months:"Juli-aug",icon:"scissors"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juli-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-maj",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:1,P:1,K:1},{month:"Apr",N:3,P:2,K:1},{month:"Maj",N:6,P:4,K:2,label:"Blomning"},{month:"Jun",N:7,P:5,K:4},{month:"Jul",N:5,P:4,K:6,label:"Nötfyllning"},{month:"Aug",N:3,P:3,K:7},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Valnöten är inte extremt krävande men uppskattar ett rejält mål på våren."},{timing:"Blomning (maj)",tip:"En giva vedaska (kaliumrik) stärker blomning och nötbildning."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Övergödsling med kväve ger frodigt bladverk men sämre nötproduktion."},{timing:"Höst",tip:"Ingen kvävegödsling efter midsommar. Mulcha med löv eller kompost som långsam näring."}],companions:{good:[{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och stör inte valnötens djupa rötter."},{name:"Vinbär",icon:"berry",why:"Tolererar valnötens juglon. Buskar under trädkronan utnyttjar utrymmet smart."},{name:"Ringblomma",icon:"flower",why:"Tolererar juglon och lockar nyttoinsekter."}],bad:[{id:"apple",name:"Äpple",icon:"fruit",why:"Äppelträd är känsliga för valnötens juglon (naturligt växtgift). Håll minst 15-20 meters avstånd."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Nattskuggväxter (tomat, potatis, paprika) är känsliga för juglon och trivs inte nära valnötsträd."}]},rotation:{avoid:[{name:"Valnöt"}],avoidWhy:"Juglon (naturligt växtgift) anrikas i jorden under ett valnötsträd. Ett nytt träd kan påverkas, men effekten avtar efter 2-3 år utan träd.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats ger bäst start.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Gröngödsla marken i minst 3 år efter att ett valnötsträd tagits bort."},varieties:[{name:"Broadview",zones:[1,2,3],note:"Kanadensisk sort från Karpaterna. Kompakt växtsätt - passar mindre trädgårdar. Självfertil! Tunnskaliga, smakrika nötter. Ger skörd efter 3-5 år (ympad)."},{name:"Buccaneer",zones:[1,2,3],note:"Han- och honblommorna överlappar alltid - utmärkt självfertil. Stora nötter (6-8 cm). Skörd oktober-november. Bra val om du bara har plats för ett träd."},{name:"Fernor",zones:[1,2,3],note:"Sen bladsprickning - minskar risken för senvårfrost rejält. Frisk sort med god härdighet. Delvis självfertil men ger bättre skörd med partner."},{name:"Loiko",zones:[1,2,3,4],note:"Samling av fröförökade plantor från Vitryssland. Utmärkt härdighet - testade i Sundsvallstrakten med lyckad skörd. Varierar i egenskaper. Spännande för odlare i zon 4."}],problems:[{name:"Senvårfrost",symptom:"Blomknoppar och unga skott svartnar efter en frostnatt. Hela årets skörd kan gå förlorad.",fix:"Välj sort med sen bladsprickning (Fernor). Plantera i en sluttning där kall luft rinner undan - aldrig i en frostficka. Unga träd kan täckas med fiberduk vid frostrisknätter."},{name:"Bakteriebrand (Xanthomonas)",symptom:"Svarta fläckar på blad och unga skott. Blad torkar och faller. Värst i fuktigt väder.",fix:"Ta bort angripna grenar. Förbättra luftcirkulationen genom beskärning. Välj friska, certifierade plantor."},{name:"Ekorrar och kråkfåglar",symptom:"Nötterna försvinner innan du hinner skörda. Kajor, kråkor och ekorrar är otroligt snabba.",fix:"Skörda så snart det gröna skalet börjar spricka! Kontrollera trädet dagligen under skördesäsongen."}],pollination:{selfFertile:!1,description:"Valnöten har både han- och honblommor på samma träd, men de blommar ofta vid olika tidpunkter (dikogami). Vissa sorter (Broadview, Buccaneer) har bra överlappning och klarar sig ensamma. Två olika sorter ger alltid bättre skörd.",groups:[{name:"Självfertila (bra överlappning)",varieties:["Broadview","Buccaneer"]},{name:"Delvis självfertila",varieties:["Fernor"]},{name:"Fröförökade (varierar)",varieties:["Loiko"]}],tip:"Vindpollinerat - insekter spelar liten roll. Har du bara plats för ett träd: välj Buccaneer (han- och honblommorna överlappar alltid) eller Broadview (självfertil). Finns det grannar med valnöt? Då löser sig pollineringen av sig själv."},establishment:{description:"Valnöten kräver tålamod de första åren. Trädet lägger energi på att etablera sin djupa pålrot - det syns inte mycket ovan mark. Men när den väl tagit fart belönar den dig i generationer.",years:[{year:"År 1-2",tasks:["Vattna regelbundet hela sommaren - pålroten etablerar sig","Skydda stammen mot gnagare (nät eller spiral)","Stamskydd mot solbränna på sydvästra sidan vintertid","Ge kompost på våren, inte för mycket kväve"]},{year:"År 3-5",tasks:["Första nötterna dyker upp (ympade träd)!","Beskär under JAS-perioden - valnöten blöder kraftigt vid vårbeskärning","Forma kronan: öppen, luftig, ljus i mitten","Vattna vid torka men trädet blir alltmer självgående"]},{year:"År 5+",tasks:["Ökande skörd år för år","Minimal skötsel - valnöten är ett av de mest lättodlade fruktträden","Fortsätt JAS-beskärning för att hålla kronan öppen","Njut av att du planterade ett träd som dina barnbarn kommer skörda"]}],protection:["Stamskydd mot gnagare - kaniner och sorkar gnager bark på unga träd","Viltskydd om rådjur finns i området","Stamskydd mot solbränna (vit kalkmjölk) vintertid","Fiberduk vid frostrisknätter under blomning de första åren"],tip:"Valnöten planterar du för dina barnbarns skull - och det är därför det är så himla speciellt när du faktiskt får nötter! Ympade sorter (Broadview, Buccaneer) ger skörd redan efter 3-5 år."},ripeningGuide:{description:"Valnötter mognar från september till november. Det gröna skalet (hullet) spricker när nöten är mogen och nöten börjar falla. Skörda snabbt - ekorrar och kråkfåglar är ännu snabbare.",entries:[{variety:"Broadview",from:"sep",to:"okt",type:"Tidig valnöt"},{variety:"Fernor",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Buccaneer",from:"okt",to:"nov",type:"Sen valnöt"},{variety:"Loiko",from:"sep",to:"okt",type:"Varierar"}],tip:"Skörda så snart det gröna skalet börjar spricka. Bär handskar - juglon färgar händerna brunaktigt och det är svårt att tvätta bort!"},goodToKnow:[{icon:"warning",title:"Juglon - valnötens hemliga vapen",text:"Alla delar av valnöten producerar juglon, ett naturligt växtgift. Äppelträd och tomater mår dåligt nära ett valnötsträd. MEN: Fritidsodlingens Riksorganisation (FOR) konstaterar att den praktiska effekten i vanliga trädgårdar är ganska begränsad. Håll känsliga växter 15-20 m bort, men panika inte.",severity:"warning"},{icon:"tip",title:"Du planterar för generationer",text:"Ett valnötsträd kan leva i 200+ år. Carl von Linne beskrev valnötsträd i södra Sverige på 1700-talet. Det är ett av få träd du kan plantera med vetskapen att det kommer ge glädje i hundratals år.",severity:"tip"},{icon:"warning",title:"Beskär ALDRIG på våren!",text:"Valnöten blöder kraftigt vid vårbeskärning - saven rinner ur snittytorna och kan skada trädet allvarligt. Beskär under JAS-perioden (juli-aug-sept) precis som alla Prunus och stenfrukter.",severity:"warning"},{icon:"tip",title:"Manchurisk valnöt - alternativet i norr",text:"I zon 4-5 kan manchurisk valnöt (Juglans mandshurica) vara ett alternativ. Den ger mindre nötter med hårdare skal, men tål -40°C. Exotiskt vackra blad (upp till 75 cm!) som bonus.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Valnötsträd planteras som ympade eller fröförökade träd. Köp ett ungt träd och plantera det en gång för alla - valnöten har en djup pålrot och tål INTE omplantering.",steps:["Gräv en grop minst dubbelt så bred som rotklumpen och rejält djup","Slå ner en stödpåle INNAN du sätter trädet","Plantera på samma djup som trädet stått i krukan","Fyll igen med uppgrävd jord blandat med kompost","Vattna rikligt - minst 30 liter","Mulcha i 1-2 meters radie runt stammen","Montera stamskydd mot gnagare"],tips:["Vårplantering ger säkrare etablering - rötterna hinner växa under sommaren","Tänk på slutstorleken! Broadview blir 6-8 m, andra sorter 10-15 m","Juglon: plantera inte nära äppelträd, tomater eller andra känsliga växter","Köp ympade namnsorter för säkrare resultat (3-5 år till skörd istället för 10-15)"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Frösådd / Ympning",biennial:!1,description:"Valnötsträd kan förökas från frö (stratifiering krävs) eller genom ympning. Fröförökade träd ger inte samma egenskaper som moderträdet och tar 8-15 år till skörd.",steps:["Samla mogna nötter på hösten","Blötlägg i vatten 24-48 timmar","Stratifiera i fuktig sand i kylskåp 4-6 veckor vid 2-5°C","Alternativt: så direkt utomhus på hösten (naturen sköter stratifieringen)","Plantera på permanent plats så tidigt som möjligt (pålroten!)","Vänta 8-15 år på skörd (frösodd) eller 3-5 år (ympad)"],isolation:"Frösodd ger unika träd med okända egenskaper.",storageYears:"Färska nötter gror bäst samma höst",tip:"Vill du föröka en namnsort identiskt? Ympning är enda sättet. Men det är svårt på egen hand - valnöten blöder kraftigt. Gå en ympkurs!"},storage:{shelfLife:"3-12 månader (beroende på metod)",methods:[{method:"Torkning + svalt förvar",icon:"cellar",duration:"6-12 månader",description:"Ta bort det gröna skalet direkt. Sprid nötterna i ett lager och torka i luftigt rum i 2-3 veckor. Förvara svalt och torrt i nätpåsar eller papperskartonger.",best:!0},{method:"Kylskåp (i skal)",icon:"snowflake",duration:"1 år",description:"Torkade nötter i skal håller sig utmärkt i kylskåpet. Perfekt om du skördar mer än du hinner äta.",best:!1},{method:"Frysning (skalade)",icon:"snowflake",duration:"2+ år",description:"Skala nötterna och frys i påsar. Håller i flera år och är alltid redo att använda i bakning och matlagning.",best:!1}],tips:["Bär handskar vid skörd - juglon färgar händerna brunaktigt","Ta bort det gröna skalet DIREKT efter skörd - annars kan kärnan bli bitter","Torka ordentligt - fuktiga nötter möglar snabbt","Förvara aldrig i plastpåse - använd nätpåsar eller papperskartonger"]},harvestCalc:{minPerSqm:5,maxPerSqm:30,unit:"kg per träd (år 8+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (den enda rätta tiden)",when:"Juli-september",description:"Valnöten blöder kraftigt vid vårbeskärning - saven rinner okontrollerat ur snittytorna. Beskär BARA under JAS-perioden när saven är lugnare och snitten torkar snabbt.",steps:["Ta bort döda, sjuka och korsande grenar","Öppna kronan för ljus och luftcirkulation","Ta bort vattenskott som växer rakt uppåt","Begränsa höjden genom att korta in toppskottet","Ta aldrig bort mer än 1/4 av kronvolymen per år"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"Det enda sättet att föröka namnsorter med garanterade egenskaper. Svårt på egen hand - valnöten blöder kraftigt. Kopulationsympning på våren.",icon:"seedling"},{method:"Frösådd",description:"Stratifiera nötterna och så utomhus. Ger unika träd med varierande egenskaper. Spännande experiment men räkna med 8-15 år till skörd.",icon:"seed"}],tip:"Ympkurser arrangeras av lokala trädgårdsföreningar. Valnötsympning är knepigare än äpple, men möjligt med rätt teknik."}};export{r as valnot};
